1143 Value *InstCombinerImpl::SimplifyMultipleUseDemandedBits(
1144     Instruction *I, const APInt &DemandedMask, KnownBits &Known, unsigned Depth,
1145     const SimplifyQuery &Q) {
1146   unsigned BitWidth = DemandedMask.getBitWidth();
1147   Type *ITy = I->getType();
1148 
1149   KnownBits LHSKnown(BitWidth);
1150   KnownBits RHSKnown(BitWidth);
1151 
1152   // Despite the fact that we can't simplify this instruction in all User's
1153   // context, we can at least compute the known bits, and we can
1154   // do simplifications that apply to *just* the one user if we know that
1155   // this instruction has a simpler value in that context.
1156   switch (I->getOpcode()) {
1157   case Instruction::And: {
1158     llvm::computeKnownBits(I->getOperand(1), RHSKnown, Depth + 1, Q);
1159     llvm::computeKnownBits(I->getOperand(0), LHSKnown, Depth + 1, Q);
1160     Known = analyzeKnownBitsFromAndXorOr(cast<Operator>(I), LHSKnown, RHSKnown,
1161                                          Depth, Q);
1162     computeKnownBitsFromContext(I, Known, Depth, Q);
1163 
1164     // If the client is only demanding bits that we know, return the known
1165     // constant.
1166     if (DemandedMask.isSubsetOf(Known.Zero | Known.One))
1167       return Constant::getIntegerValue(ITy, Known.One);
1168 
1169     // If all of the demanded bits are known 1 on one side, return the other.
1170     // These bits cannot contribute to the result of the 'and' in this context.
1171     if (DemandedMask.isSubsetOf(LHSKnown.Zero | RHSKnown.One))
1172       return I->getOperand(0);
1173     if (DemandedMask.isSubsetOf(RHSKnown.Zero | LHSKnown.One))
1174       return I->getOperand(1);
1175 
1176     break;
1177   }
1178   case Instruction::Or: {
1179     llvm::computeKnownBits(I->getOperand(1), RHSKnown, Depth + 1, Q);
1180     llvm::computeKnownBits(I->getOperand(0), LHSKnown, Depth + 1, Q);
1181     Known = analyzeKnownBitsFromAndXorOr(cast<Operator>(I), LHSKnown, RHSKnown,
1182                                          Depth, Q);
1183     computeKnownBitsFromContext(I, Known, Depth, Q);
1184 
1185     // If the client is only demanding bits that we know, return the known
1186     // constant.
1187     if (DemandedMask.isSubsetOf(Known.Zero | Known.One))
1188       return Constant::getIntegerValue(ITy, Known.One);
1189 
1190     // We can simplify (X|Y) -> X or Y in the user's context if we know that
1191     // only bits from X or Y are demanded.
1192     // If all of the demanded bits are known zero on one side, return the other.
1193     // These bits cannot contribute to the result of the 'or' in this context.
1194     if (DemandedMask.isSubsetOf(LHSKnown.One | RHSKnown.Zero))
1195       return I->getOperand(0);
1196     if (DemandedMask.isSubsetOf(RHSKnown.One | LHSKnown.Zero))
1197       return I->getOperand(1);
1198 
1199     break;
1200   }
1201   case Instruction::Xor: {
1202     llvm::computeKnownBits(I->getOperand(1), RHSKnown, Depth + 1, Q);
1203     llvm::computeKnownBits(I->getOperand(0), LHSKnown, Depth + 1, Q);
1204     Known = analyzeKnownBitsFromAndXorOr(cast<Operator>(I), LHSKnown, RHSKnown,
1205                                          Depth, Q);
1206     computeKnownBitsFromContext(I, Known, Depth, Q);
1207 
1208     // If the client is only demanding bits that we know, return the known
1209     // constant.
1210     if (DemandedMask.isSubsetOf(Known.Zero | Known.One))
1211       return Constant::getIntegerValue(ITy, Known.One);
1212 
1213     // We can simplify (X^Y) -> X or Y in the user's context if we know that
1214     // only bits from X or Y are demanded.
1215     // If all of the demanded bits are known zero on one side, return the other.
1216     if (DemandedMask.isSubsetOf(RHSKnown.Zero))
1217       return I->getOperand(0);
1218     if (DemandedMask.isSubsetOf(LHSKnown.Zero))
1219       return I->getOperand(1);
1220 
1221     break;
1222   }
1223   case Instruction::Add: {
1224     unsigned NLZ = DemandedMask.countl_zero();
1225     APInt DemandedFromOps = APInt::getLowBitsSet(BitWidth, BitWidth - NLZ);
1226 
1227     // If an operand adds zeros to every bit below the highest demanded bit,
1228     // that operand doesn't change the result. Return the other side.
1229     llvm::computeKnownBits(I->getOperand(1), RHSKnown, Depth + 1, Q);
1230     if (DemandedFromOps.isSubsetOf(RHSKnown.Zero))
1231       return I->getOperand(0);
1232 
1233     llvm::computeKnownBits(I->getOperand(0), LHSKnown, Depth + 1, Q);
1234     if (DemandedFromOps.isSubsetOf(LHSKnown.Zero))
1235       return I->getOperand(1);
