104 /// This function attempts to replace V with a simpler value based on the
105 /// demanded bits. When this function is called, it is known that only the bits
106 /// set in DemandedMask of the result of V are ever used downstream.
107 /// Consequently, depending on the mask and V, it may be possible to replace V
108 /// with a constant or one of its operands. In such cases, this function does
109 /// the replacement and returns true. In all other cases, it returns false after
110 /// analyzing the expression and setting KnownOne and known to be one in the
111 /// expression. Known.Zero contains all the bits that are known to be zero in
112 /// the expression. These are provided to potentially allow the caller (which
113 /// might recursively be SimplifyDemandedBits itself) to simplify the
114 /// expression.
115 /// Known.One and Known.Zero always follow the invariant that:
116 ///   Known.One & Known.Zero == 0.
117 /// That is, a bit can't be both 1 and 0. The bits in Known.One and Known.Zero
118 /// are accurate even for bits not in DemandedMask. Note
119 /// also that the bitwidth of V, DemandedMask, Known.Zero and Known.One must all
120 /// be the same.
121 ///
122 /// This returns null if it did not change anything and it permits no
123 /// simplification.  This returns V itself if it did some simplification of V's
124 /// operands based on the information about what bits are demanded. This returns
125 /// some other non-null value if it found out that V is equal to another value
126 /// in the context where the specified bits are demanded, but not for all users.
127 Value *InstCombinerImpl::SimplifyDemandedUseBits(Value *V, APInt DemandedMask,
128                                                  KnownBits &Known,
129                                                  unsigned Depth,
130                                                  const SimplifyQuery &Q) {
131   assert(V != nullptr && "Null pointer of Value???");
132   assert(Depth <= MaxAnalysisRecursionDepth && "Limit Search Depth");
133   uint32_t BitWidth = DemandedMask.getBitWidth();
134   Type *VTy = V->getType();
135   assert(
136       (!VTy->isIntOrIntVectorTy() || VTy->getScalarSizeInBits() == BitWidth) &&
137       Known.getBitWidth() == BitWidth &&
138       "Value *V, DemandedMask and Known must have same BitWidth");
139 
140   if (isa<Constant>(V)) {
141     llvm::computeKnownBits(V, Known, Depth, Q);
142     return nullptr;
143   }
144 
145   Known.resetAll();
146   if (DemandedMask.isZero()) // Not demanding any bits from V.
147     return UndefValue::get(VTy);
148 
149   if (Depth == MaxAnalysisRecursionDepth)
150     return nullptr;
151 
152   Instruction *I = dyn_cast<Instruction>(V);
153   if (!I) {
154     llvm::computeKnownBits(V, Known, Depth, Q);
155     return nullptr;        // Only analyze instructions.
156   }
157 
158   // If there are multiple uses of this value and we aren't at the root, then
159   // we can't do any simplifications of the operands, because DemandedMask
160   // only reflects the bits demanded by *one* of the users.
161   if (Depth != 0 && !I->hasOneUse())
162     return SimplifyMultipleUseDemandedBits(I, DemandedMask, Known, Depth, Q);
163 
164   KnownBits LHSKnown(BitWidth), RHSKnown(BitWidth);
165   // If this is the root being simplified, allow it to have multiple uses,
166   // just set the DemandedMask to all bits so that we can try to simplify the
167   // operands.  This allows visitTruncInst (for example) to simplify the
168   // operand of a trunc without duplicating all the logic below.
169   if (Depth == 0 && !V->hasOneUse())
170     DemandedMask.setAllBits();
171 
172   // Update flags after simplifying an operand based on the fact that some high
173   // order bits are not demanded.
174   auto disableWrapFlagsBasedOnUnusedHighBits = [](Instruction *I,
175                                                   unsigned NLZ) {
176     if (NLZ > 0) {
177       // Disable the nsw and nuw flags here: We can no longer guarantee that
178       // we won't wrap after simplification. Removing the nsw/nuw flags is
179       // legal here because the top bit is not demanded.
180       I->setHasNoSignedWrap(false);
181       I->setHasNoUnsignedWrap(false);
182     }
183     return I;
184   };
185 
186   // If the high-bits of an ADD/SUB/MUL are not demanded, then we do not care
187   // about the high bits of the operands.
188   auto simplifyOperandsBasedOnUnusedHighBits = [&](APInt &DemandedFromOps) {
189     unsigned NLZ = DemandedMask.countl_zero();
190     // Right fill the mask of bits for the operands to demand the most
191     // significant bit and all those below it.
192     DemandedFromOps = APInt::getLowBitsSet(BitWidth, BitWidth - NLZ);
193     if (ShrinkDemandedConstant(I, 0, DemandedFromOps) ||
194         SimplifyDemandedBits(I, 0, DemandedFromOps, LHSKnown, Depth + 1, Q) ||
195         ShrinkDemandedConstant(I, 1, DemandedFromOps) ||
196         SimplifyDemandedBits(I, 1, DemandedFromOps, RHSKnown, Depth + 1, Q)) {
197       disableWrapFlagsBasedOnUnusedHighBits(I, NLZ);
198       return true;
199     }
200     return false;
201   };
202 
203   switch (I->getOpcode()) {
204   default:
205     llvm::computeKnownBits(I, Known, Depth, Q);
206     break;
207   case Instruction::And: {
208     // If either the LHS or the RHS are Zero, the result is zero.
209     if (SimplifyDemandedBits(I, 1, DemandedMask, RHSKnown, Depth + 1, Q) ||
210         SimplifyDemandedBits(I, 0, DemandedMask & ~RHSKnown.Zero, LHSKnown,
211                              Depth + 1, Q))
212       return I;
213 
214     Known = analyzeKnownBitsFromAndXorOr(cast<Operator>(I), LHSKnown, RHSKnown,
215                                          Depth, Q);
216 
217     // If the client is only demanding bits that we know, return the known
218     // constant.
219     if (DemandedMask.isSubsetOf(Known.Zero | Known.One))
220       return Constant::getIntegerValue(VTy, Known.One);
221 
222     // If all of the demanded bits are known 1 on one side, return the other.
223     // These bits cannot contribute to the result of the 'and'.
224     if (DemandedMask.isSubsetOf(LHSKnown.Zero | RHSKnown.One))
225       return I->getOperand(0);
226     if (DemandedMask.isSubsetOf(RHSKnown.Zero | LHSKnown.One))
227       return I->getOperand(1);
228 
229     // If the RHS is a constant, see if we can simplify it.
230     if (ShrinkDemandedConstant(I, 1, DemandedMask & ~LHSKnown.Zero))
231       return I;
232 
233     break;
234   }
235   case Instruction::Or: {
236     // If either the LHS or the RHS are One, the result is One.
237     if (SimplifyDemandedBits(I, 1, DemandedMask, RHSKnown, Depth + 1, Q) ||
238         SimplifyDemandedBits(I, 0, DemandedMask & ~RHSKnown.One, LHSKnown,
239                              Depth + 1, Q)) {
240       // Disjoint flag may not longer hold.
241       I->dropPoisonGeneratingFlags();
242       return I;
243     }
244 
245     Known = analyzeKnownBitsFromAndXorOr(cast<Operator>(I), LHSKnown, RHSKnown,
246                                          Depth, Q);
247 
